import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";
import { LayoutDashboard, ShoppingBag, Package, Folder, Users } from "lucide-react"; // dùng icon chuyên nghiệp

const AdminLayout = () => {
  const location = useLocation();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard", icon: <LayoutDashboard size={18} /> },
    { name: "Sản phẩm", path: "/admin/products", icon: <ShoppingBag size={18} /> },
    { name: "Đơn hàng", path: "/admin/orders", icon: <Package size={18} /> },
    { name: "Danh mục", path: "/admin/categories", icon: <Folder size={18} /> },
    { name: "Người dùng", path: "/admin/users", icon: <Users size={18} /> },
  ];

  const currentPage =
    location.pathname.replace("/admin/", "").toUpperCase() || "DASHBOARD";
  const isDashboard = location.pathname === "/admin/dashboard";

  return (
    <div className="flex min-h-screen bg-gray-50 text-gray-800 font-inter text-[15px] leading-relaxed">
      {/* Sidebar */}
      <aside className="w-60 bg-white border-r border-gray-200 p-5 flex flex-col shadow-sm">
        {/* Logo / Profile */}
        <Link
          to="/"
          className="flex items-center mb-8 space-x-3 px-2 py-2 rounded-md hover:bg-gray-100 transition"
        >
          <div className="w-10 h-10 bg-pink-500 text-white flex items-center justify-center rounded-full font-semibold shadow-sm">
            A
          </div>
          <div>
            <p className="font-semibold text-sm text-gray-800">Admin</p>
            <p className="text-xs text-gray-500">DTP Flower Shop</p>
          </div>
        </Link>

        {/* Navigation */}
        <nav className="flex flex-col gap-1 flex-1">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center gap-3 px-3 py-2 rounded-md text-sm font-medium transition ${
                location.pathname === item.path
                  ? "bg-pink-100 text-pink-600 font-semibold"
                  : "text-gray-700 hover:bg-gray-100 hover:text-pink-600"
              }`}
            >
              {item.icon}
              <span>{item.name}</span>
            </Link>
          ))}

          <a
            href="/"
            className="mt-auto text-center bg-pink-500 text-white py-2 rounded-md text-sm font-semibold shadow hover:bg-pink-600 transition"
          >
            🌸 Trang chính
          </a>
        </nav>
      </aside>

      {/* Main content */}
      <main className="flex-1 p-6 overflow-y-auto">
        {/* Header */}
        <header className="flex justify-between items-center mb-6 border-b border-gray-200 pb-3">
          <h1 className="text-xl font-semibold text-gray-800 tracking-wide">
            {currentPage}
          </h1>
        </header>

        {/* Page content */}
        <section
          className={`bg-white rounded-xl shadow-sm p-6 min-h-[70vh] ${
            isDashboard ? "border border-pink-100" : ""
          }`}
        >
          <Outlet />
        </section>
      </main>
    </div>
  );
};

export default AdminLayout;
